// Scope: src/store.js changes only (BUG-001-A, BUG-001-B). FIRST-compliant per
// skills/unit-tests-FIRST.md — fixed literal inputs, fresh state per test, exact assertions.

import { test, beforeEach } from "node:test";
import assert from "node:assert/strict";
import { reset, addExpense, listExpenses, summarize } from "../../src/store.js";

beforeEach(() => reset());

// --- BUG-001-A: `to` bound must be inclusive ---

test("listExpenses: expense dated exactly `to` → included (regression BUG-001-A)", () => {
  addExpense({ amount: 12, category: "food", date: "2026-07-31" });
  const result = listExpenses({ from: "2026-07-01", to: "2026-07-31" });
  assert.equal(result.length, 1);
  assert.equal(result[0].date, "2026-07-31");
});

test("listExpenses: expense dated after `to` → excluded", () => {
  addExpense({ amount: 12, category: "food", date: "2026-08-01" });
  const result = listExpenses({ from: "2026-07-01", to: "2026-07-31" });
  assert.equal(result.length, 0);
});

test("listExpenses: from === to selects exactly that single day", () => {
  addExpense({ amount: 1, category: "food", date: "2026-07-14" });
  addExpense({ amount: 2, category: "food", date: "2026-07-15" });
  addExpense({ amount: 3, category: "food", date: "2026-07-16" });
  const result = listExpenses({ from: "2026-07-15", to: "2026-07-15" });
  assert.equal(result.length, 1);
  assert.equal(result[0].date, "2026-07-15");
});

// --- BUG-001-B: exact decimal money totals ---

test("summarize: 10.10 + 20.20 → total exactly 30.3 (regression BUG-001-B)", () => {
  addExpense({ amount: 10.1, category: "food", date: "2026-07-02" });
  addExpense({ amount: 20.2, category: "travel", date: "2026-07-03" });
  const summary = summarize();
  assert.equal(summary.total, 30.3);
});

test("summarize: per-category subtotals are exact decimals", () => {
  addExpense({ amount: 0.1, category: "food", date: "2026-07-01" });
  addExpense({ amount: 0.1, category: "food", date: "2026-07-02" });
  addExpense({ amount: 0.1, category: "food", date: "2026-07-03" });
  const summary = summarize();
  assert.equal(summary.byCategory.food, 0.3);
  assert.equal(summary.total, 0.3);
});

test("summarize: date-filtered summary includes the `to` day (fixes compose)", () => {
  addExpense({ amount: 10.1, category: "food", date: "2026-07-30" });
  addExpense({ amount: 20.2, category: "food", date: "2026-07-31" });
  addExpense({ amount: 99, category: "food", date: "2026-08-01" });
  const summary = summarize({ from: "2026-07-01", to: "2026-07-31" });
  assert.equal(summary.count, 2);
  assert.equal(summary.total, 30.3);
});
